#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m;
int num,dfn[N],low[N],stk[N],top;
int cnt,c[N],sz[N];
int head[N],ver[N<<1],nxt[N<<1],tot;
int d[N],f[N];
long long ans;
queue<int> q;
vector<pair<int,int>> g[N];
bool dis[N<<1],ins[N];

void add(int x,int y,int z){
    ver[++tot]=y,dis[tot]=z,nxt[tot]=head[x],head[x]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x];i;i=nxt[i])
        if(!dfn[ver[i]]){
            tarjan(ver[i]);
            low[x]=min(low[x],low[ver[i]]);
        }else if(ins[ver[i]])
            low[x]=min(low[x],dfn[ver[i]]);
    if(dfn[x]==low[x]){
        cnt++;
        int t;
        do{
            t=stk[top--],ins[t]=0,c[t]=cnt;
            sz[cnt]++;
        }while(t!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,x,a,b;i<=m;i++){
        scanf("%d%d%d",&x,&a,&b);
        if(x==1)
            add(a,b,0),add(b,a,0);
        if(x==2)
            add(a,b,1);
        if(x==3)
            add(b,a,0);
        if(x==4)
            add(b,a,1);
        if(x==5)
            add(a,b,0);
    }
    for(int i=1;i<=n;i++)
        if(!dfn[i])
            tarjan(i);
    for(int i=1;i<=n;i++)
        for(int j=head[i];j;j=nxt[j])
            if(c[i]==c[ver[j]] && dis[j]){
                printf("-1");
                return 0;
            }else if(c[i]!=c[ver[j]])
                g[c[i]].push_back(make_pair(c[ver[j]],dis[j])),d[c[ver[j]]]++;
    for(int i=1;i<=cnt;i++){
        f[i]=1;
        if(!d[i])
            q.push(i);
    }
    while(q.size()){
        int x=q.front();
        q.pop();
        ans+=1LL*f[x]*sz[x];
        for(pair<int,int> y:g[x]){
            f[y.first]=max(f[y.first],f[x]+y.second);
            if(!--d[y.first])
                q.push(y.first);
        }
    }
    printf("%lld",ans);
    return 0;
}
